import { CategoryValueSleepAnalysis } from '@kingstinct/react-native-healthkit';
import type { CategorySampleTyped } from '@kingstinct/react-native-healthkit';

import { HEALTHKIT_SLEEP_CATEGORY } from '@/health/wearableSleep.const';

type TSleepCategorySample = CategorySampleTyped<typeof HEALTHKIT_SLEEP_CATEGORY>;

const HK_VALUE_LABEL: Record<number, string> = {
  [CategoryValueSleepAnalysis.inBed]: 'inBed',
  [CategoryValueSleepAnalysis.asleepUnspecified]: 'asleepUnspecified',
  [CategoryValueSleepAnalysis.awake]: 'awake',
  [CategoryValueSleepAnalysis.asleepCore]: 'asleepCore',
  [CategoryValueSleepAnalysis.asleepDeep]: 'asleepDeep',
  [CategoryValueSleepAnalysis.asleepREM]: 'asleepREM',
};

function serializeMetadata(metadata: TSleepCategorySample['metadata']): Record<string, unknown> | null {
  if (!metadata || typeof metadata !== 'object') {
    return null;
  }
  const entries = Object.entries(metadata as Record<string, unknown>);
  if (entries.length === 0) {
    return null;
  }
  const out: Record<string, unknown> = {};
  for (const [key, value] of entries) {
    if (value === undefined) {
      continue;
    }
    out[key] = value;
  }
  return Object.keys(out).length > 0 ? out : null;
}

/** Лог сырых HealthKit SleepAnalysis сэмплов до map/dedupe (только __DEV__) */
export function logRawHealthKitSleepSamples(
  samples: readonly TSleepCategorySample[],
  context: {
    /** Откуда вызвали */
    source: string;
    /** Начало окна запроса */
    rangeStart: Date;
    /** Конец окна запроса */
    rangeEnd: Date;
  },
): void {
  if (!__DEV__) {
    return;
  }

  const byValue: Record<string, number> = {};
  const bySource: Record<string, number> = {};
  const unknownValues = new Set<number>();

  const rows = samples.map((sample) => {
    const label = HK_VALUE_LABEL[sample.value] ?? `unknown(${sample.value})`;
    byValue[label] = (byValue[label] ?? 0) + 1;
    if (HK_VALUE_LABEL[sample.value] === undefined) {
      unknownValues.add(sample.value);
    }

    const sourceName = sample.sourceRevision?.source?.name ?? '?';
    const sourceBundleId = sample.sourceRevision?.source?.bundleIdentifier ?? '?';
    const sourceKey = `${sourceName} | ${sourceBundleId}`;
    bySource[sourceKey] = (bySource[sourceKey] ?? 0) + 1;

    const durationMin = Math.round(
      (sample.endDate.getTime() - sample.startDate.getTime()) / 60_000,
    );

    return {
      value: sample.value,
      stage: label,
      start: sample.startDate.toISOString(),
      end: sample.endDate.toISOString(),
      durationMin,
      sourceName,
      sourceBundleId,
      uuid: 'uuid' in sample ? (sample as { uuid?: string }).uuid : undefined,
      metadata: serializeMetadata(sample.metadata),
    };
  });

  // eslint-disable-next-line no-console -- temporary raw HK calibration
  console.log('[SleepScore:rawHK]', {
    source: context.source,
    rangeStart: context.rangeStart.toISOString(),
    rangeEnd: context.rangeEnd.toISOString(),
    sampleCount: samples.length,
    byValue,
    bySource,
    unknownValues: [...unknownValues],
  });
  // eslint-disable-next-line no-console -- temporary raw HK calibration
  console.log('[SleepScore:rawHK] samples (copy)', rows);
}

import type { IWearableHistoryNight } from '@/health/bucketWearableSegmentsByNight';
import type { ISleepScoreResult } from '@/health/sleepScore.typings';
import {
  SLEEP_SCORE_AWAKENINGS_GOOD_MAX,
  SLEEP_SCORE_AWAKENINGS_POOR_MIN,
  SLEEP_SCORE_EFFICIENCY_CEILING,
  SLEEP_SCORE_EFFICIENCY_FLOOR,
  SLEEP_SCORE_WASO_GOOD_MAX,
  SLEEP_SCORE_WASO_POOR_MIN,
} from '@/health/sleepScore.const';

/** Строка калибровки efficiency / continuity для одной ночи */
export interface ISleepScoreCalibrationRow {
  /** Дата пробуждения */
  nightDate: string;
  /** TST, мин */
  tst: number;
  /** Time in bed, мин */
  inBed: number | undefined;
  /** Сырая efficiency 0–1 */
  efficiencyRaw: number | null;
  /** Efficiency score 0–100 */
  efficiencyScore: number | null;
  /** WASO, мин */
  waso: number;
  /** Число пробуждений */
  awakenings: number;
  /** Continuity score 0–100 */
  continuityScore: number | null;
  /** Минуты inBed из стадий */
  stageInBed: number;
  /** Минуты awake из стадий */
  stageAwake: number;
  /** Минуты asleep* из стадий */
  stageAsleep: number;
}

function buildCalibrationRows(
  nights: IWearableHistoryNight[],
  scores: ISleepScoreResult[],
): ISleepScoreCalibrationRow[] {
  return nights.map((night, index) => {
    const input = night.scoreInput;
    const score = scores[index];
    const inBed = input.timeInBedMinutes;
    let efficiencyRaw: number | null = null;
    if (inBed !== undefined && inBed > 0 && input.totalSleepMinutes > 0) {
      efficiencyRaw = Math.min(1, input.totalSleepMinutes / inBed);
    }

    const stageMinutes = night.summary.stageMinutes;
    const stageAsleep =
      (stageMinutes.asleepCore ?? 0) +
      (stageMinutes.asleepDeep ?? 0) +
      (stageMinutes.asleepREM ?? 0) +
      (stageMinutes.asleepUnspecified ?? 0);

    return {
      nightDate: night.nightDate,
      tst: input.totalSleepMinutes,
      inBed,
      efficiencyRaw,
      efficiencyScore: score?.components.efficiency ?? null,
      waso: input.wasoMinutes,
      awakenings: input.awakeningCount,
      continuityScore: score?.components.continuity ?? null,
      stageInBed: stageMinutes.inBed ?? 0,
      stageAwake: stageMinutes.awake ?? 0,
      stageAsleep: Math.round(stageAsleep),
    };
  });
}

/** Лог сырых данных efficiency/continuity для калибровки (только __DEV__) */
export function logSleepScoreCalibration(
  nights: IWearableHistoryNight[],
  scores: ISleepScoreResult[],
): void {
  if (!__DEV__ || nights.length === 0) {
    return;
  }

  const rows = buildCalibrationRows(nights, scores);
  const thresholds = {
    efficiencyFloor: SLEEP_SCORE_EFFICIENCY_FLOOR,
    efficiencyCeiling: SLEEP_SCORE_EFFICIENCY_CEILING,
    wasoGoodMax: SLEEP_SCORE_WASO_GOOD_MAX,
    wasoPoorMin: SLEEP_SCORE_WASO_POOR_MIN,
    awakeningsGoodMax: SLEEP_SCORE_AWAKENINGS_GOOD_MAX,
    awakeningsPoorMin: SLEEP_SCORE_AWAKENINGS_POOR_MIN,
  };

  // eslint-disable-next-line no-console -- temporary calibration aid for SH-55
  console.log('[SleepScore:calibrate] thresholds', thresholds);
  // eslint-disable-next-line no-console -- temporary calibration aid for SH-55
  console.log(
    '[SleepScore:calibrate] nights (copy this table)',
    rows.map((row) => ({
      ...row,
      efficiencyPct:
        row.efficiencyRaw === null ? null : Math.round(row.efficiencyRaw * 1000) / 10,
      note:
        row.stageInBed === 0 && row.stageAwake === 0
          ? 'no_inBed_no_awake'
          : undefined,
    })),
  );
}

import { copy } from '@/copy/ru';
import type {
  ISleepWearableNightSummary,
  TWearableSleepQualityTier,
} from '@/health/healthKitSleep.typings';
import { WEARABLE_SLEEP_NORM_MAX_MINUTES, findWearableSourceHintPattern } from '@/health/wearableSleep.const';

function padTimePart(value: number): string {
  return String(value).padStart(2, '0');
}

/** Форматирует время сна для UI */
export function formatWearableClockTime(date: Date): string {
  return `${padTimePart(date.getHours())}:${padTimePart(date.getMinutes())}`;
}

/** Форматирует длительность сна */
export function formatWearableSleepDuration(totalMinutes: number): string {
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;

  if (hours > 0 && minutes > 0) {
    return copy.sleep.wearableDurationHoursMinutes
      .replace('{hours}', String(hours))
      .replace('{minutes}', String(minutes));
  }

  if (hours > 0) {
    return copy.sleep.wearableDurationHoursOnly.replace('{hours}', String(hours));
  }

  return copy.sleep.wearableDurationMinutesOnly.replace('{minutes}', String(minutes));
}

/** Диапазон засыпания и подъёма */
export function formatWearableBedtimeRange(summary: ISleepWearableNightSummary): string | null {
  if (!summary.fellAsleepAt || !summary.wokeAt) {
    return null;
  }

  return `${formatWearableClockTime(summary.fellAsleepAt)}${copy.sleep.wearableBedtimeSeparator}${formatWearableClockTime(summary.wokeAt)}`;
}

/** Доля заполнения полоски относительно верхней границы нормы */
export function computeWearableSleepNormProgress(totalMinutes: number): number {
  if (totalMinutes <= 0) {
    return 0;
  }

  return Math.min(1, totalMinutes / WEARABLE_SLEEP_NORM_MAX_MINUTES);
}

/** Человекочитаемое имя источника сна */
export function formatWearableSourceName(
  sourceName?: string,
  sourceBundleId?: string,
): string {
  const haystack = `${sourceName ?? ''} ${sourceBundleId ?? ''}`;
  const hintPattern = findWearableSourceHintPattern(haystack);

  if (hintPattern === 'polar') {
    return 'Polar';
  }
  if (hintPattern === 'oura') {
    return 'Oura';
  }
  if (hintPattern === 'garmin') {
    return 'Garmin';
  }
  if (hintPattern === 'whoop') {
    return 'Whoop';
  }
  if (hintPattern === 'watch' || hintPattern === 'apple') {
    return 'Apple Watch';
  }

  if (sourceName && sourceName !== 'SourceProxy') {
    return sourceName;
  }

  return copy.sleep.wearableSectionTitle;
}

/** Человекочитаемый уровень качества сна */
export function wearableSleepQualityLabel(tier: TWearableSleepQualityTier): string {
  if (tier === 'excellent') {
    return copy.sleep.wearableQualityExcellent;
  }
  if (tier === 'good') {
    return copy.sleep.wearableQualityGood;
  }
  if (tier === 'fair') {
    return copy.sleep.wearableQualityFair;
  }
  return copy.sleep.wearableQualityPoor;
}

/** Строка оценки качества сна для UI */
export function formatWearableSleepQuality(summary: ISleepWearableNightSummary): string | null {
  if (summary.sleepQualityScore === undefined || summary.sleepQualityTier === undefined) {
    return null;
  }

  return formatSleepScoreValue(summary.sleepQualityScore, summary.sleepQualityTier);
}

/** Строка score · label */
export function formatSleepScoreValue(
  score: number,
  tier: TWearableSleepQualityTier,
): string {
  return copy.sleep.wearableQualityValue
    .replace('{score}', String(score))
    .replace('{label}', wearableSleepQualityLabel(tier));
}

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';

import type { IWearableHistoryNight } from '@/health/bucketWearableSegmentsByNight';
import type {
  ISleepWearableNightSummary,
  TWearableSleepStatus,
} from '@/health/healthKitSleep.typings';
import { aggregateSleepScoreTrend } from '@/health/aggregateSleepScoreTrend';
import { buildSleepScoreMethodDetails } from '@/health/buildSleepScoreMethodDetails';
import { computeSleepScoresForHistory } from '@/health/computeSleepScore';
import { loadWearableSleepHistory } from '@/health/loadWearableSleepHistory';
import type {
  ISleepScoreMethodDetails,
  ISleepScoreResult,
  ISleepScoreTrend,
  TSleepScoreTrendDays,
} from '@/health/sleepScore.typings';
import { useSleepScheduleStore } from '@/store/sleepScheduleStore';

const WEARABLE_SLEEP_HISTORY_STALE_MS = 5 * 60 * 1000;

export interface IUseWearableSleepScoreOptions {
  /** Дата выбранной ночи YYYY-MM-DD */
  selectedNightDate: string | null;
  /** Окно тренда */
  trendDays: TSleepScoreTrendDays;
  /** Запрашивать данные */
  enabled?: boolean;
}

export interface IUseWearableSleepScoreResult {
  /** Статус истории */
  status: TWearableSleepStatus | null;
  /** Сводка выбранной ночи из кэша */
  selectedSummary: ISleepWearableNightSummary | null;
  /** Score выбранной ночи */
  selectedNightScore: ISleepScoreResult | null;
  /** Детали методики для шторы */
  methodDetails: ISleepScoreMethodDetails | null;
  /** Тренд за 7/30 дней */
  trend: ISleepScoreTrend | null;
  /** Идёт первая загрузка */
  isLoading: boolean;
}

/** Один кэш истории (~31 ночь); смена дня — только select */
export function useWearableSleepScore(
  options: IUseWearableSleepScoreOptions,
): IUseWearableSleepScoreResult {
  const { selectedNightDate, trendDays, enabled = true } = options;
  const nightSchedule = useSleepScheduleStore((s) => s.schedule);

  const query = useQuery({
    queryKey: [
      'wearable-sleep-history',
      nightSchedule.bedtime,
      nightSchedule.wakeTime,
    ],
    enabled,
    staleTime: WEARABLE_SLEEP_HISTORY_STALE_MS,
    queryFn: () => loadWearableSleepHistory(nightSchedule),
  });

  const nights: IWearableHistoryNight[] = query.data?.nights ?? [];
  const status = query.data?.status ?? null;

  const nightScores = useMemo(
    () => computeSleepScoresForHistory(nights.map((night) => night.scoreInput)),
    [nights],
  );

  const selectedIndex = useMemo(() => {
    if (!selectedNightDate) {
      return -1;
    }
    return nights.findIndex((night) => night.nightDate === selectedNightDate);
  }, [nights, selectedNightDate]);

  const selectedSummary =
    selectedIndex >= 0 ? nights[selectedIndex].summary : null;
  const selectedNightScore =
    selectedIndex >= 0 ? nightScores[selectedIndex] ?? null : null;

  const methodDetails = useMemo(() => {
    if (selectedIndex < 0 || !selectedNightScore) {
      return null;
    }
    return buildSleepScoreMethodDetails(
      nights.map((night) => night.scoreInput),
      selectedIndex,
      selectedNightScore,
    );
  }, [nights, selectedIndex, selectedNightScore]);

  const trend = useMemo(
    () => aggregateSleepScoreTrend(nightScores, trendDays),
    [nightScores, trendDays],
  );

  return {
    status,
    selectedSummary,
    selectedNightScore,
    methodDetails,
    trend,
    isLoading: query.isPending,
  };
}

