import { wearableSleepQualityTier } from '@/health/scoreWearableSleepQuality';
import { SLEEP_SCORE_BASELINE_NIGHTS } from '@/health/sleepScore.const';
import type {
  ISleepScoreComponents,
  ISleepScoreResult,
  ISleepScoreTrend,
  TSleepScoreTrendDays,
} from '@/health/sleepScore.typings';

function averageNullable(values: (number | null)[]): number | null {
  const present = values.filter((value): value is number => value !== null);
  if (present.length === 0) {
    return null;
  }
  return present.reduce((sum, value) => sum + value, 0) / present.length;
}

/** Усредняет scores за последние `trendDays` ночей с данными */
export function aggregateSleepScoreTrend(
  nightScores: ISleepScoreResult[],
  trendDays: TSleepScoreTrendDays,
): ISleepScoreTrend | null {
  if (nightScores.length === 0) {
    return null;
  }

  const window = nightScores.slice(-trendDays);
  const scoreSum = window.reduce((sum, night) => sum + night.score, 0);
  const score = Math.round(scoreSum / window.length);

  const components: ISleepScoreComponents = {
    duration: averageNullable(window.map((night) => night.components.duration)),
    efficiency: averageNullable(window.map((night) => night.components.efficiency)),
    continuity: averageNullable(window.map((night) => night.components.continuity)),
    consistency: averageNullable(window.map((night) => night.components.consistency)),
  };

  if (components.duration !== null) {
    components.duration = Math.round(components.duration);
  }
  if (components.efficiency !== null) {
    components.efficiency = Math.round(components.efficiency);
  }
  if (components.continuity !== null) {
    components.continuity = Math.round(components.continuity);
  }
  if (components.consistency !== null) {
    components.consistency = Math.round(components.consistency);
  }

  const last = window[window.length - 1];
  const isColdStart = nightScores.length < SLEEP_SCORE_BASELINE_NIGHTS;

  return {
    score,
    components,
    tier: wearableSleepQualityTier(score),
    isColdStart,
    belowRecommendedNorm: last.belowRecommendedNorm,
    nightCount: window.length,
    trendDays,
  };
}

import type { ISleepWearableNightSummary, ISleepWearableSegment } from '@/health/healthKitSleep.typings';
import { ASLEEP_WEARABLE_STAGES } from '@/health/wearableSleep.const';

function durationMinutes(startAt: Date, endAt: Date): number {
  return Math.max(0, (endAt.getTime() - startAt.getTime()) / 60_000);
}

function isAsleepStage(stage: ISleepWearableSegment['stage']): boolean {
  return ASLEEP_WEARABLE_STAGES.includes(stage);
}

function accumulateStageMinutes(
  segments: ISleepWearableSegment[],
): Partial<Record<ISleepWearableSegment['stage'], number>> {
  const stageMinutes: Partial<Record<ISleepWearableSegment['stage'], number>> = {};

  for (const segment of segments) {
    const minutes = durationMinutes(segment.startAt, segment.endAt);
    stageMinutes[segment.stage] = (stageMinutes[segment.stage] ?? 0) + minutes;
  }

  return stageMinutes;
}

function pickPrimarySource(segments: ISleepWearableSegment[]): {
  name?: string;
  bundleId?: string;
} {
  const totals = new Map<string, { name: string; bundleId: string; minutes: number }>();

  for (const segment of segments) {
    if (!isAsleepStage(segment.stage)) {
      continue;
    }
    const minutes = durationMinutes(segment.startAt, segment.endAt);
    const existing = totals.get(segment.sourceBundleId);
    if (existing) {
      existing.minutes += minutes;
      continue;
    }
    totals.set(segment.sourceBundleId, {
      name: segment.sourceName,
      bundleId: segment.sourceBundleId,
      minutes,
    });
  }

  let best: { name: string; bundleId: string; minutes: number } | undefined;

  for (const entry of totals.values()) {
    if (!best || entry.minutes > best.minutes) {
      best = entry;
    }
  }

  if (!best) {
    return {};
  }

  return {
    name: best.name,
    bundleId: best.bundleId,
  };
}

/** Агрегирует дедуплицированные сегменты в сводку за ночь */
export function aggregateWearableNight(
  segments: ISleepWearableSegment[],
): ISleepWearableNightSummary | null {
  if (segments.length === 0) {
    return null;
  }

  const stageMinutes = accumulateStageMinutes(segments);
  const asleepSegments = segments.filter((segment) => isAsleepStage(segment.stage));

  let fellAsleepAt: Date | undefined;
  let wokeAt: Date | undefined;
  let totalSleepMinutes = 0;

  if (asleepSegments.length > 0) {
    fellAsleepAt = asleepSegments.reduce(
      (earliest, segment) => (segment.startAt < earliest ? segment.startAt : earliest),
      asleepSegments[0].startAt,
    );
    wokeAt = asleepSegments.reduce(
      (latest, segment) => (segment.endAt > latest ? segment.endAt : latest),
      asleepSegments[0].endAt,
    );
    totalSleepMinutes = asleepSegments.reduce(
      (sum, segment) => sum + durationMinutes(segment.startAt, segment.endAt),
      0,
    );
  } else {
    const inBedSegments = segments.filter((segment) => segment.stage === 'inBed');
    if (inBedSegments.length > 0) {
      fellAsleepAt = inBedSegments[0].startAt;
      wokeAt = inBedSegments[inBedSegments.length - 1].endAt;
      totalSleepMinutes = inBedSegments.reduce(
        (sum, segment) => sum + durationMinutes(segment.startAt, segment.endAt),
        0,
      );
    }
  }

  if (totalSleepMinutes <= 0) {
    return null;
  }

  const primarySource = pickPrimarySource(segments);
  return {
    fellAsleepAt,
    wokeAt,
    totalSleepMinutes: Math.round(totalSleepMinutes),
    stageMinutes,
    primarySourceName: primarySource.name,
    primarySourceBundleId: primarySource.bundleId,
  };
}

import type { ISleepNightWindow } from '@/domain/sleepNight.typings';
import type { INightSchedule } from '@/domain/nightSchedule.typings';
import { DEFAULT_NIGHT_SCHEDULE } from '@/domain/nightSchedule';
import { aggregateWearableNight } from '@/health/aggregateWearableNight';
import { buildWearableQueryWindow } from '@/health/buildWearableQueryWindow';
import type {
  ISleepWearableNightSummary,
  ISleepWearableSegment,
  TWearableSleepStatus,
} from '@/health/healthKitSleep.typings';
import type { ISleepScoreNightInput } from '@/health/sleepScore.typings';
import {
  measureSleepContinuity,
  resolveTimeInBedMinutes,
} from '@/health/sleepScoreFromSegments';

/** Ночь истории: сводка + вход для формулы */
export interface IWearableHistoryNight {
  /** Дата пробуждения */
  nightDate: string;
  /** Окно ночи */
  window: ISleepNightWindow;
  /** Агрегированная сводка */
  summary: ISleepWearableNightSummary;
  /** Сегменты после дедупа в query-окне */
  segments: ISleepWearableSegment[];
  /** Вход для computeSleepScore */
  scoreInput: ISleepScoreNightInput;
}

/** Результат batch-загрузки истории сна */
export interface IWearableSleepHistoryResult {
  /** Статус доступа / данных */
  status: TWearableSleepStatus;
  /** Ночи с данными, по возрастанию даты */
  nights: IWearableHistoryNight[];
}

function segmentOverlapsRange(
  segment: ISleepWearableSegment,
  startAt: Date,
  endAt: Date,
): boolean {
  return segment.startAt < endAt && segment.endAt > startAt;
}

/** Раскладывает сегменты по ночным окнам и строит score inputs */
export function bucketWearableSegmentsByNight(
  segments: ISleepWearableSegment[],
  windows: ISleepNightWindow[],
  schedule: INightSchedule = DEFAULT_NIGHT_SCHEDULE,
): IWearableHistoryNight[] {
  const nights: IWearableHistoryNight[] = [];

  for (const window of windows) {
    const queryWindow = buildWearableQueryWindow(window, schedule);
    const nightSegments = segments.filter((segment) =>
      segmentOverlapsRange(segment, queryWindow.startAt, queryWindow.endAt),
    );
    if (nightSegments.length === 0) {
      continue;
    }

    const summary = aggregateWearableNight(nightSegments);
    if (summary === null || summary.totalSleepMinutes === undefined) {
      continue;
    }

    const continuity = measureSleepContinuity(nightSegments);
    const timeInBedMinutes = resolveTimeInBedMinutes(summary, nightSegments);

    nights.push({
      nightDate: window.nightDate,
      window,
      summary,
      segments: nightSegments,
      scoreInput: {
        nightDate: window.nightDate,
        totalSleepMinutes: summary.totalSleepMinutes,
        timeInBedMinutes,
        fellAsleepAt: summary.fellAsleepAt,
        wokeAt: summary.wokeAt,
        wasoMinutes: continuity.wasoMinutes,
        awakeningCount: continuity.awakeningCount,
        continuityHasSignal: continuity.hasSignal,
      },
    });
  }

  return nights;
}

import {
  baselineDurationModifier,
  clinicalDurationScore,
} from '@/health/computeDurationScore';
import {
  bedtimeAnchorMinutes,
  clockMinutesFromMidnight,
} from '@/health/computeConsistencyScore';
import {
  SLEEP_SCORE_BASELINE_NIGHTS,
  sleepScoreAgeBand,
} from '@/health/sleepScore.const';
import type {
  ISleepScoreConsistencyMethod,
  ISleepScoreDurationMethod,
  ISleepScoreMethodDetails,
  ISleepScoreNightInput,
  ISleepScoreResult,
} from '@/health/sleepScore.typings';
import { median, sampleStdDev } from '@/health/sleepScoreMath';

function rollingWindowNights(
  nights: ISleepScoreNightInput[],
  endIndex: number,
  windowSize: number,
): ISleepScoreNightInput[] {
  const start = Math.max(0, endIndex - windowSize + 1);
  return nights.slice(start, endIndex + 1);
}

/** Детали методики duration + consistency для выбранной ночи */
export function buildSleepScoreMethodDetails(
  nights: ISleepScoreNightInput[],
  nightIndex: number,
  scoreResult: ISleepScoreResult,
  ageYears?: number,
): ISleepScoreMethodDetails | null {
  const night = nights[nightIndex];
  if (!night) {
    return null;
  }

  const ageBand = sleepScoreAgeBand(ageYears);
  const clinicalScore = Math.round(clinicalDurationScore(night.totalSleepMinutes, ageBand));
  const window = rollingWindowNights(nights, nightIndex, SLEEP_SCORE_BASELINE_NIGHTS);
  const baselineReady = window.length >= SLEEP_SCORE_BASELINE_NIGHTS;
  const baselineMinutes = baselineReady
    ? median(window.map((entry) => entry.totalSleepMinutes))
    : undefined;
  const appliedBaseline = !scoreResult.isColdStart && baselineMinutes !== undefined;
  const baselineModifier = appliedBaseline
    ? baselineDurationModifier(night.totalSleepMinutes, baselineMinutes)
    : 0;

  const duration: ISleepScoreDurationMethod = {
    tstMinutes: night.totalSleepMinutes,
    clinicalScore,
    baselineMinutes,
    baselineModifier,
    appliedBaseline,
    durationScore: scoreResult.components.duration ?? 0,
  };

  const consistencyNights = window.map((entry) => ({
    nightDate: entry.nightDate,
    fellAsleepAt: entry.fellAsleepAt,
    wokeAt: entry.wokeAt,
  }));

  let consistency: ISleepScoreConsistencyMethod = {
    isCollecting: scoreResult.isColdStart || scoreResult.components.consistency === null,
    nightCount: window.length,
    consistencyScore: scoreResult.components.consistency,
    nights: consistencyNights,
  };

  if (!consistency.isCollecting) {
    const fellAsleepAts = window
      .map((entry) => entry.fellAsleepAt)
      .filter((value): value is Date => value !== undefined);
    const wokeAts = window
      .map((entry) => entry.wokeAt)
      .filter((value): value is Date => value !== undefined);

    if (fellAsleepAts.length >= 2 && wokeAts.length >= 2) {
      const bedtimeStdMinutes = sampleStdDev(fellAsleepAts.map(bedtimeAnchorMinutes));
      const wakeStdMinutes = sampleStdDev(wokeAts.map(clockMinutesFromMidnight));
      consistency = {
        ...consistency,
        bedtimeStdMinutes: Math.round(bedtimeStdMinutes),
        wakeStdMinutes: Math.round(wakeStdMinutes),
        avgStdMinutes: Math.round((bedtimeStdMinutes + wakeStdMinutes) / 2),
      };
    }
  }

  return { duration, consistency };
}

