function jsDayToWeekdayId(day: number): TWeekdayId {
  const map: TWeekdayId[] = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];
  return map[day] ?? 'mon';
}

function formatNightDate(date: Date): string {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function addDays(date: Date, days: number): Date {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}

function buildFallbackWindow(
  eveningDate: Date,
  schedule: INightSchedule,
): { startAt: Date; endAt: Date } {
  const bedtime = parseTimeParts(schedule.bedtime);
  const wake = parseTimeParts(schedule.wakeTime);

  const startAt = new Date(eveningDate);
  startAt.setHours(bedtime.hours, bedtime.minutes, 0, 0);

  const endAt = addDays(eveningDate, 1);
  endAt.setHours(wake.hours, wake.minutes, 0, 0);

  return { startAt, endAt };
}

/** Строит N ночных окон по schedule; nightDate — дата пробуждения */
export function buildWearableHistoryWindows(
  historyEnd: Date = new Date(),
  schedule: INightSchedule = DEFAULT_NIGHT_SCHEDULE,
  nightCount: number = WEARABLE_SLEEP_HISTORY_NIGHTS,
): ISleepNightWindow[] {
  const anchor = startOfLocalDay(historyEnd);
  const firstWakeDate = addDays(anchor, -(nightCount - 1));
  const windows: ISleepNightWindow[] = [];

  for (let index = 0; index < nightCount; index += 1) {
    const wakeDate = addDays(firstWakeDate, index);
    const eveningDate = addDays(wakeDate, -1);
    const fallback = buildFallbackWindow(eveningDate, schedule);

    windows.push({
      nightDate: formatNightDate(wakeDate),
      weekdayId: jsDayToWeekdayId(wakeDate.getDay()),
      startAt: fallback.startAt,
      endAt: fallback.endAt,
      hasScenarioData: false,
    });
  }

  return windows;
}

import {
  SLEEP_SCORE_CONSISTENCY_GOOD_MAX,
  SLEEP_SCORE_CONSISTENCY_POOR_MIN,
} from '@/health/sleepScore.const';
import { lerpClamped, sampleStdDev } from '@/health/sleepScoreMath';

/** Минуты от локальной полуночи (с учётом перехода через сутки для bedtime) */
export function clockMinutesFromMidnight(date: Date): number {
  return date.getHours() * 60 + date.getMinutes() + date.getSeconds() / 60;
}

/**
 * Bedtime как минуты относительно якоря 18:00 предыдущего дня,
 * чтобы 23:00 и 01:00 были на одной шкале.
 */
export function bedtimeAnchorMinutes(fellAsleepAt: Date): number {
  const minutes = clockMinutesFromMidnight(fellAsleepAt);
  const anchor = 18 * 60;
  if (minutes >= anchor) {
    return minutes - anchor;
  }
  return minutes + (24 * 60 - anchor);
}

/** Consistency score по stddev отбоя и подъёма; null если меньше 2 ночей */
export function computeConsistencyScore(
  fellAsleepAts: Date[],
  wokeAts: Date[],
): number | null {
  if (fellAsleepAts.length < 2 || wokeAts.length < 2) {
    return null;
  }

  const bedtimeMinutes = fellAsleepAts.map(bedtimeAnchorMinutes);
  const wakeMinutes = wokeAts.map(clockMinutesFromMidnight);
  const avgStd =
    (sampleStdDev(bedtimeMinutes) + sampleStdDev(wakeMinutes)) / 2;

  if (avgStd <= SLEEP_SCORE_CONSISTENCY_GOOD_MAX) {
    return 100;
  }
  if (avgStd >= SLEEP_SCORE_CONSISTENCY_POOR_MIN) {
    return 0;
  }

  return Math.round(
    lerpClamped(
      avgStd,
      SLEEP_SCORE_CONSISTENCY_GOOD_MAX,
      SLEEP_SCORE_CONSISTENCY_POOR_MIN,
      100,
      0,
    ),
  );
}

import {
  SLEEP_SCORE_AWAKENINGS_GOOD_MAX,
  SLEEP_SCORE_AWAKENINGS_POOR_MIN,
  SLEEP_SCORE_WASO_GOOD_MAX,
  SLEEP_SCORE_WASO_POOR_MIN,
} from '@/health/sleepScore.const';
import { lerpClamped } from '@/health/sleepScoreMath';

function scoreFromRange(
  value: number,
  goodMax: number,
  poorMin: number,
): number {
  if (value <= goodMax) {
    return 100;
  }
  if (value >= poorMin) {
    return 0;
  }
  return lerpClamped(value, goodMax, poorMin, 100, 0);
}

/** Continuity score по WASO и числу пробуждений */
export function computeContinuityScore(
  wasoMinutes: number,
  awakeningCount: number,
): number {
  const wasoScore = scoreFromRange(
    wasoMinutes,
    SLEEP_SCORE_WASO_GOOD_MAX,
    SLEEP_SCORE_WASO_POOR_MIN,
  );
  const awakeningScore = scoreFromRange(
    awakeningCount,
    SLEEP_SCORE_AWAKENINGS_GOOD_MAX,
    SLEEP_SCORE_AWAKENINGS_POOR_MIN,
  );
  return Math.round(Math.min(wasoScore, awakeningScore));
}

import {
  SLEEP_SCORE_BASELINE_BONUS_CLOSE,
  SLEEP_SCORE_BASELINE_BONUS_NEAR,
  SLEEP_SCORE_BASELINE_DEV_CLOSE,
  SLEEP_SCORE_BASELINE_DEV_NEAR,
  sleepScoreAgeBand,
} from '@/health/sleepScore.const';
import type { TSleepScoreAgeBand } from '@/health/sleepScore.typings';
import { clampScore, lerpClamped } from '@/health/sleepScoreMath';

/** Клинический duration score для взрослых 18–64 */
function clinicalDurationAdult(tstMinutes: number): number {
  if (tstMinutes < 240) {
    return 0;
  }
  if (tstMinutes < 360) {
    return lerpClamped(tstMinutes, 240, 360, 0, 60);
  }
  if (tstMinutes < 420) {
    return lerpClamped(tstMinutes, 360, 420, 60, 100);
  }
  if (tstMinutes <= 540) {
    return 100;
  }
  if (tstMinutes < 600) {
    return lerpClamped(tstMinutes, 540, 600, 100, 85);
  }
  if (tstMinutes < 720) {
    return lerpClamped(tstMinutes, 600, 720, 85, 45);
  }
  return 30;
}

/** Клинический duration score для 65+ */
function clinicalDurationOlder(tstMinutes: number): number {
  if (tstMinutes < 240) {
    return 0;
  }
  if (tstMinutes < 360) {
    return lerpClamped(tstMinutes, 240, 360, 0, 60);
  }
  if (tstMinutes < 420) {
    return lerpClamped(tstMinutes, 360, 420, 60, 100);
  }
  if (tstMinutes <= 480) {
    return 100;
  }
  if (tstMinutes < 540) {
    return lerpClamped(tstMinutes, 480, 540, 100, 90);
  }
  if (tstMinutes < 600) {
    return lerpClamped(tstMinutes, 540, 600, 90, 85);
  }
  if (tstMinutes < 720) {
    return lerpClamped(tstMinutes, 600, 720, 85, 45);
  }
  return 30;
}

/** Клинический скор по TST и возрастной группе */
export function clinicalDurationScore(
  tstMinutes: number,
  ageBand: TSleepScoreAgeBand,
): number {
  if (ageBand === 'older') {
    return clinicalDurationOlder(tstMinutes);
  }
  return clinicalDurationAdult(tstMinutes);
}

/** Модификатор baseline по |TST − median|, 0 / 5 / 10 */
export function baselineDurationModifier(
  tstMinutes: number,
  baselineMinutes: number | undefined,
): number {
  if (baselineMinutes === undefined) {
    return 0;
  }
  const deviation = Math.abs(tstMinutes - baselineMinutes);
  if (deviation <= SLEEP_SCORE_BASELINE_DEV_CLOSE) {
    return SLEEP_SCORE_BASELINE_BONUS_CLOSE;
  }
  if (deviation <= SLEEP_SCORE_BASELINE_DEV_NEAR) {
    return SLEEP_SCORE_BASELINE_BONUS_NEAR;
  }
  return 0;
}

export interface IComputeDurationScoreParams {
  /** TST сегодня, минуты */
  tstMinutes: number;
  /** Медиана TST за rolling 7 ночей; undefined в cold start */
  baselineMinutes?: number;
  /** Применять baseline modifier */
  applyBaselineModifier: boolean;
  /** Возраст пользователя, лет */
  ageYears?: number;
}

/** Duration score 0–100 */
export function computeDurationScore(params: IComputeDurationScoreParams): number {
  const ageBand = sleepScoreAgeBand(params.ageYears);
  const clinical = clinicalDurationScore(params.tstMinutes, ageBand);

  if (!params.applyBaselineModifier) {
    return clampScore(clinical);
  }

  const modifier = baselineDurationModifier(params.tstMinutes, params.baselineMinutes);
  return clampScore(clinical + modifier);
}

import {
  SLEEP_SCORE_EFFICIENCY_CEILING,
  SLEEP_SCORE_EFFICIENCY_FLOOR,
} from '@/health/sleepScore.const';
import { lerpClamped } from '@/health/sleepScoreMath';

/** Efficiency score 0–100; null если нет валидного time in bed */
export function computeEfficiencyScore(
  totalSleepMinutes: number,
  timeInBedMinutes: number | undefined,
): number | null {
  if (timeInBedMinutes === undefined || timeInBedMinutes <= 0) {
    return null;
  }
  if (totalSleepMinutes <= 0) {
    return 0;
  }

  const efficiency = Math.min(1, totalSleepMinutes / timeInBedMinutes);

  if (efficiency < SLEEP_SCORE_EFFICIENCY_FLOOR) {
    return 0;
  }
  if (efficiency >= SLEEP_SCORE_EFFICIENCY_CEILING) {
    return 100;
  }

  return Math.round(
    lerpClamped(
      efficiency,
      SLEEP_SCORE_EFFICIENCY_FLOOR,
      SLEEP_SCORE_EFFICIENCY_CEILING,
      0,
      100,
    ),
  );
}

import assert from 'node:assert/strict';
import { describe, it } from 'node:test';

import { computeDurationScore, clinicalDurationScore } from '@/health/computeDurationScore';
