    assert.equal(computeContinuityScore(10, 4), 0);
  });
});

describe('computeConsistencyScore', () => {
  it('returns null with fewer than 2 nights', () => {
    assert.equal(
      computeConsistencyScore([new Date('2026-07-01T23:00:00')], [new Date('2026-07-02T07:00:00')]),
      null,
    );
  });

  it('returns 100 for stable schedule', () => {
    const beds = [
      new Date('2026-07-01T23:00:00'),
      new Date('2026-07-02T23:05:00'),
      new Date('2026-07-03T22:55:00'),
    ];
    const wakes = [
      new Date('2026-07-02T07:00:00'),
      new Date('2026-07-03T07:05:00'),
      new Date('2026-07-04T06:55:00'),
    ];
    const score = computeConsistencyScore(beds, wakes);
    assert.ok(score !== null);
    assert.ok((score as number) >= 90);
  });
});

describe('computeSleepScore', () => {
  it('uses cold start without consistency for fewer than 7 nights', () => {
    const nights = Array.from({ length: 3 }, (_, index) =>
      night(`2026-07-0${index + 1}`, 480),
    );
    const result = computeSleepScore({ nights, nightIndex: 2 });
    assert.equal(result.isColdStart, true);
    assert.equal(result.components.consistency, null);
    assert.equal(result.belowRecommendedNorm, false);
  });

  it('flags below recommended norm', () => {
    const nights = [night('2026-07-01', 360)];
    const result = computeSleepScore({ nights, nightIndex: 0 });
    assert.equal(result.belowRecommendedNorm, true);
  });

  it('skips efficiency and continuity without signal', () => {
    const nights = [
      night('2026-07-01', 400, {
        timeInBedMinutes: undefined,
        wasoMinutes: 0,
        awakeningCount: 0,
        continuityHasSignal: false,
      }),
    ];
    const result = computeSleepScore({ nights, nightIndex: 0 });
    assert.equal(result.components.efficiency, null);
    assert.equal(result.components.continuity, null);
  });

  it('applies consistency after 7 nights', () => {
    const nights = Array.from({ length: 7 }, (_, index) => {
      const day = String(index + 1).padStart(2, '0');
      return night(`2026-07-${day}`, 480);
    });
    const result = computeSleepScore({ nights, nightIndex: 6 });
    assert.equal(result.isColdStart, false);
    assert.ok(result.components.consistency !== null);
  });
});

describe('aggregateSleepScoreTrend', () => {
  it('averages last N night scores', () => {
    const nights = Array.from({ length: 10 }, (_, index) => {
      const day = String(index + 1).padStart(2, '0');
      return night(`2026-07-${day}`, 480);
    });
    const scores = nights.map((_, nightIndex) =>
      computeSleepScore({ nights, nightIndex }),
    );
    const trend7 = aggregateSleepScoreTrend(scores, 7);
    assert.ok(trend7);
    assert.equal(trend7?.nightCount, 7);
    assert.equal(trend7?.trendDays, 7);
  });
});

import { computeConsistencyScore } from '@/health/computeConsistencyScore';
import { computeContinuityScore } from '@/health/computeContinuityScore';
import { computeDurationScore } from '@/health/computeDurationScore';
import { computeEfficiencyScore } from '@/health/computeEfficiencyScore';
import { wearableSleepQualityTier } from '@/health/scoreWearableSleepQuality';
import {
  SLEEP_SCORE_BASELINE_NIGHTS,
  SLEEP_SCORE_RECOMMENDED_TST_MINUTES,
  SLEEP_SCORE_WEIGHT_CONSISTENCY,
  SLEEP_SCORE_WEIGHT_CONTINUITY,
  SLEEP_SCORE_WEIGHT_DURATION,
  SLEEP_SCORE_WEIGHT_EFFICIENCY,
} from '@/health/sleepScore.const';
import type {
  ISleepScoreComponents,
  ISleepScoreNightInput,
  ISleepScoreResult,
} from '@/health/sleepScore.typings';
import { median } from '@/health/sleepScoreMath';

function weightedAverage(
  parts: { score: number; weight: number }[],
): number {
  const totalWeight = parts.reduce((sum, part) => sum + part.weight, 0);
  if (totalWeight <= 0) {
    return 0;
  }
  const sum = parts.reduce((acc, part) => acc + part.score * part.weight, 0);
  return sum / totalWeight;
}

function rollingWindowNights(
  nights: ISleepScoreNightInput[],
  endIndex: number,
  windowSize: number,
): ISleepScoreNightInput[] {
  const start = Math.max(0, endIndex - windowSize + 1);
  return nights.slice(start, endIndex + 1);
}

/** Baseline median TST по rolling окну (включая текущую ночь) */
export function resolveBaselineMinutes(
  nights: ISleepScoreNightInput[],
  nightIndex: number,
): number | undefined {
  const window = rollingWindowNights(nights, nightIndex, SLEEP_SCORE_BASELINE_NIGHTS);
  if (window.length < SLEEP_SCORE_BASELINE_NIGHTS) {
    return undefined;
  }
  return median(window.map((night) => night.totalSleepMinutes));
}

/** Средний TST за rolling 7 ночей до nightIndex включительно */
export function rollingAverageTst(
  nights: ISleepScoreNightInput[],
  nightIndex: number,
): number | undefined {
  const window = rollingWindowNights(nights, nightIndex, SLEEP_SCORE_BASELINE_NIGHTS);
  if (window.length === 0) {
    return undefined;
  }
  const sum = window.reduce((acc, night) => acc + night.totalSleepMinutes, 0);
  return sum / window.length;
}

export interface IComputeSleepScoreParams {
  /** Ночи по возрастанию nightDate */
  nights: ISleepScoreNightInput[];
  /** Индекс ночи для score */
  nightIndex: number;
  /** Возраст, лет */
  ageYears?: number;
}

/** Собирает weighted sleep score для одной ночи */
export function computeSleepScore(params: IComputeSleepScoreParams): ISleepScoreResult {
  const { nights, nightIndex, ageYears } = params;
  const night = nights[nightIndex];
  const nightsWithData = nights.length;
  const isColdStart = nightsWithData < SLEEP_SCORE_BASELINE_NIGHTS;

  const baselineMinutes = resolveBaselineMinutes(nights, nightIndex);
  const duration = computeDurationScore({
    tstMinutes: night.totalSleepMinutes,
    baselineMinutes,
    applyBaselineModifier: !isColdStart && baselineMinutes !== undefined,
    ageYears,
  });

  const efficiency = computeEfficiencyScore(
    night.totalSleepMinutes,
    night.timeInBedMinutes,
  );

  let continuity: number | null = null;
  if (night.continuityHasSignal) {
    continuity = computeContinuityScore(night.wasoMinutes, night.awakeningCount);
  }

  const consistencyWindow = rollingWindowNights(
    nights,
    nightIndex,
    SLEEP_SCORE_BASELINE_NIGHTS,
  );
  let consistency: number | null = null;
  if (!isColdStart && consistencyWindow.length >= SLEEP_SCORE_BASELINE_NIGHTS) {
    const fellAsleepAts = consistencyWindow
      .map((entry) => entry.fellAsleepAt)
      .filter((value): value is Date => value !== undefined);
    const wokeAts = consistencyWindow
      .map((entry) => entry.wokeAt)
      .filter((value): value is Date => value !== undefined);
    consistency = computeConsistencyScore(fellAsleepAts, wokeAts);
  }

  const components: ISleepScoreComponents = {
    duration,
    efficiency,
    continuity,
    consistency,
  };

  const parts: { score: number; weight: number }[] = [
    { score: duration, weight: SLEEP_SCORE_WEIGHT_DURATION },
  ];
  if (efficiency !== null) {
    parts.push({ score: efficiency, weight: SLEEP_SCORE_WEIGHT_EFFICIENCY });
  }
  if (continuity !== null) {
    parts.push({ score: continuity, weight: SLEEP_SCORE_WEIGHT_CONTINUITY });
  }
  if (consistency !== null) {
    parts.push({ score: consistency, weight: SLEEP_SCORE_WEIGHT_CONSISTENCY });
  }

  const score = Math.round(weightedAverage(parts));

  const avg7 = rollingAverageTst(nights, nightIndex);
  const belowRecommendedNorm =
    night.totalSleepMinutes < SLEEP_SCORE_RECOMMENDED_TST_MINUTES ||
    (avg7 !== undefined && avg7 < SLEEP_SCORE_RECOMMENDED_TST_MINUTES);

  return {
    score,
    components,
    isColdStart,
    belowRecommendedNorm,
    tier: wearableSleepQualityTier(score),
  };
}

/** Считает score для каждой ночи в истории */
export function computeSleepScoresForHistory(
  nights: ISleepScoreNightInput[],
  ageYears?: number,
): ISleepScoreResult[] {
  return nights.map((_, nightIndex) =>
    computeSleepScore({ nights, nightIndex, ageYears }),
  );
}

import Healthkit, { AuthorizationRequestStatus, AuthorizationStatus } from '@kingstinct/react-native-healthkit';
import { Platform } from 'react-native';

import type { ISleepNightWindow } from '@/domain/sleepNight.typings';
import type { INightSchedule } from '@/domain/nightSchedule.typings';
import { DEFAULT_NIGHT_SCHEDULE } from '@/domain/nightSchedule';
import { aggregateWearableNight } from '@/health/aggregateWearableNight';
import { buildWearableQueryWindow } from '@/health/buildWearableQueryWindow';
import { dedupeSleepSegments } from '@/health/dedupeSleepSegments';
import type { IWearableSleepNightResult } from '@/health/healthKitSleep.typings';
import { mapHealthKitSleepSamples } from '@/health/mapHealthKitSleep';
import { getWearableMockPreset, loadMockWearableSleepNight } from '@/health/mockWearableSleep';
import { HEALTHKIT_SLEEP_CATEGORY } from '@/health/wearableSleep.const';

/**
 * Запрашивает чтение сна, если система ещё не спрашивала.
 * authorizationStatusFor отражает только запись (sharing), не чтение —
 * для read-only типов он часто sharingDenied даже при выданном доступе.
 */
export async function ensureSleepReadAuthorization(): Promise<'ready' | 'denied' | 'unavailable'> {
  if (Platform.OS !== 'ios') {
    return 'unavailable';
  }

  const available = await Healthkit.isHealthDataAvailableAsync();
  if (!available) {
    return 'unavailable';
  }

  const requestStatus = await Healthkit.getRequestStatusForAuthorization({
    toRead: [HEALTHKIT_SLEEP_CATEGORY],
  });

  if (requestStatus === AuthorizationRequestStatus.shouldRequest) {
    await Healthkit.requestAuthorization({
      toRead: [HEALTHKIT_SLEEP_CATEGORY],
    });

    const statusAfter = await Healthkit.authorizationStatusFor(HEALTHKIT_SLEEP_CATEGORY);
    if (statusAfter === AuthorizationStatus.sharingDenied) {
      return 'denied';
    }
  }

  return 'ready';
}

/** Загружает wearable-данные за ночное окно */
export async function loadWearableSleepNight(
  nightWindow: ISleepNightWindow,
  schedule: INightSchedule = DEFAULT_NIGHT_SCHEDULE,
): Promise<IWearableSleepNightResult> {
  const mockPreset = getWearableMockPreset();
  if (mockPreset !== null) {
    return loadMockWearableSleepNight(mockPreset, nightWindow.startAt, nightWindow.endAt);
  }

  try {
    const auth = await ensureSleepReadAuthorization();
    if (auth === 'unavailable') {
      return { status: 'unavailable' };
    }
    if (auth === 'denied') {
      return { status: 'denied' };
    }

    const queryWindow = buildWearableQueryWindow(nightWindow, schedule);

    const samples = await Healthkit.queryCategorySamples(HEALTHKIT_SLEEP_CATEGORY, {
      filter: {
        date: {
          startDate: queryWindow.startAt,
          endDate: queryWindow.endAt,
        },
      },
      ascending: true,
      limit: 0,
    });

    const mapped = mapHealthKitSleepSamples(samples);
    if (mapped.length === 0) {
      return { status: 'no_data' };
    }

    const deduped = dedupeSleepSegments(mapped);
    const summary = aggregateWearableNight(deduped);
    if (summary === null) {
      return { status: 'no_data' };
    }

    return {
      status: 'available',
      summary,
    };
  } catch {
    return { status: 'error' };
  }
}

/** Стадия сна из HealthKit */
export type TSleepWearableStage =
  | 'inBed'
  | 'awake'
  | 'asleepCore'
  | 'asleepDeep'
  | 'asleepREM'
  | 'asleepUnspecified';

/** Статус доступа к данным о сне с носимого */
export type TWearableSleepStatus = 'available' | 'denied' | 'unavailable' | 'no_data' | 'error';

/** Пресет мок-данных wearable для разработки */
export type TWearableMockPreset = 'default' | 'empty' | 'denied' | 'dualSource' | 'fragmented';

/** Уровень качества сна с трекера */
export type TWearableSleepQualityTier = 'excellent' | 'good' | 'fair' | 'poor';

/** Один интервал сна из HealthKit после маппинга */
export interface ISleepWearableSegment {
  /** Начало интервала */
  startAt: Date;
  /** Конец интервала */
  endAt: Date;
  /** Стадия */
  stage: TSleepWearableStage;
  /** Имя источника (Polar, Apple Watch, …) */
  sourceName: string;
  /** Bundle ID источника — для приоритета */
  sourceBundleId: string;
  /** Оценка из метаданных трекера, 0–100 */
  trackerSleepScore?: number;
}

/** Сводка по сну с носимого за ночь */
export interface ISleepWearableNightSummary {
  /** Время засыпания (первый asleep*) */
  fellAsleepAt?: Date;
  /** Время пробуждения (последний asleep* / конец inBed) */
  wokeAt?: Date;
  /** Длительность сна, мин */
  totalSleepMinutes?: number;
  /** Длительность по стадиям, мин */
  stageMinutes: Partial<Record<TSleepWearableStage, number>>;
  /** Доминирующий источник после дедупликации */
  primarySourceName?: string;
  /** Bundle ID доминирующего источника */
  primarySourceBundleId?: string;
  /** Оценка качества сна из метаданных трекера, 0–100 */
  sleepQualityScore?: number;
  /** Уровень качества для UI */
  sleepQualityTier?: TWearableSleepQualityTier;
}

/** Результат загрузки wearable-данных за ночное окно */
export interface IWearableSleepNightResult {
  /** Статус доступа */
  status: TWearableSleepStatus;
  /** Сводка, если status === 'available' */
  summary?: ISleepWearableNightSummary;
}

import Healthkit from '@kingstinct/react-native-healthkit';
import { Platform } from 'react-native';

import type { INightSchedule } from '@/domain/nightSchedule.typings';
import { DEFAULT_NIGHT_SCHEDULE } from '@/domain/nightSchedule';
import { buildWearableHistoryWindows } from '@/health/buildWearableHistoryWindows';
import { buildWearableQueryWindow } from '@/health/buildWearableQueryWindow';
import type { IWearableSleepHistoryResult } from '@/health/bucketWearableSegmentsByNight';
import { bucketWearableSegmentsByNight } from '@/health/bucketWearableSegmentsByNight';
import { dedupeSleepSegments } from '@/health/dedupeSleepSegments';
import { ensureSleepReadAuthorization } from '@/health/healthKitClient';
import { mapHealthKitSleepSamples } from '@/health/mapHealthKitSleep';
import {
  getWearableMockPreset,
  loadMockWearableSleepHistory,
} from '@/health/mockWearableSleep';
import { HEALTHKIT_SLEEP_CATEGORY } from '@/health/wearableSleep.const';

export type { IWearableSleepHistoryResult } from '@/health/bucketWearableSegmentsByNight';

/** Загружает ~31 ночь одним запросом HealthKit */
export async function loadWearableSleepHistory(
  schedule: INightSchedule = DEFAULT_NIGHT_SCHEDULE,
  historyEnd: Date = new Date(),
): Promise<IWearableSleepHistoryResult> {
  const windows = buildWearableHistoryWindows(historyEnd, schedule);
  const mockPreset = getWearableMockPreset();
  if (mockPreset !== null) {
    return loadMockWearableSleepHistory(mockPreset, windows, schedule);
  }

  if (Platform.OS !== 'ios') {
    return { status: 'unavailable', nights: [] };
  }

  try {
    const auth = await ensureSleepReadAuthorization();
    if (auth === 'unavailable') {
      return { status: 'unavailable', nights: [] };
    }
    if (auth === 'denied') {
      return { status: 'denied', nights: [] };
    }

    if (windows.length === 0) {
      return { status: 'no_data', nights: [] };
    }

    const firstWindow = windows[0];
    const lastWindow = windows[windows.length - 1];
    const rangeStart = buildWearableQueryWindow(firstWindow, schedule).startAt;
    const rangeEnd = buildWearableQueryWindow(lastWindow, schedule).endAt;

    const samples = await Healthkit.queryCategorySamples(HEALTHKIT_SLEEP_CATEGORY, {
      filter: {
        date: {
          startDate: rangeStart,
          endDate: rangeEnd,
        },
      },
      ascending: true,
      limit: 0,
    });

    const mapped = mapHealthKitSleepSamples(samples);
    if (mapped.length === 0) {
      return { status: 'no_data', nights: [] };
    }

    const deduped = dedupeSleepSegments(mapped);
    const nights = bucketWearableSegmentsByNight(deduped, windows, schedule);
    if (nights.length === 0) {
      return { status: 'no_data', nights: [] };
    }

    return { status: 'available', nights };
  } catch {
    return { status: 'error', nights: [] };
  }
}

import { Platform } from 'react-native';

import type { ISleepNightWindow } from '@/domain/sleepNight.typings';
import type { INightSchedule } from '@/domain/nightSchedule.typings';
import { DEFAULT_NIGHT_SCHEDULE } from '@/domain/nightSchedule';
import { aggregateWearableNight } from '@/health/aggregateWearableNight';
import { bucketWearableSegmentsByNight } from '@/health/bucketWearableSegmentsByNight';
import { dedupeSleepSegments } from '@/health/dedupeSleepSegments';
import type {
  ISleepWearableSegment,
  IWearableSleepNightResult,
  TWearableMockPreset,
} from '@/health/healthKitSleep.typings';
import type { IWearableSleepHistoryResult } from '@/health/bucketWearableSegmentsByNight';

const VALID_PRESETS: readonly TWearableMockPreset[] = [
  'default',
  'empty',
  'denied',
  'dualSource',
  'fragmented',
];

function addMinutes(date: Date, minutes: number): Date {
  return new Date(date.getTime() + minutes * 60_000);
}

function segment(
  startAt: Date,
  durationMin: number,
  stage: ISleepWearableSegment['stage'],
  sourceName: string,
  sourceBundleId: string,
  trackerSleepScore?: number,
): ISleepWearableSegment {
  return {
    startAt,
    endAt: addMinutes(startAt, durationMin),
    stage,
    sourceName,
    sourceBundleId,
    ...(trackerSleepScore !== undefined ? { trackerSleepScore } : {}),
  };
}

/** Активный пресет моков или null на iOS без env */
export function getWearableMockPreset(): TWearableMockPreset | null {
  const raw = process.env.EXPO_PUBLIC_WEARABLE_MOCK;
  if (raw && VALID_PRESETS.includes(raw as TWearableMockPreset)) {
    return raw as TWearableMockPreset;
  }

  if (Platform.OS !== 'ios') {
    if (process.env.NODE_ENV === 'test') {
      return 'default';
    }
    return null;
  }

  return null;
}

function buildDefaultNightSegments(windowStart: Date): ISleepWearableSegment[] {
  const bedtime = addMinutes(windowStart, 30);
  return [
    segment(bedtime, 15, 'inBed', 'Polar Flow', 'fi.polar.polarflow'),
    segment(addMinutes(bedtime, 15), 90, 'asleepCore', 'Polar Flow', 'fi.polar.polarflow', 82),
    segment(addMinutes(bedtime, 105), 55, 'asleepDeep', 'Polar Flow', 'fi.polar.polarflow', 82),
    segment(addMinutes(bedtime, 160), 70, 'asleepREM', 'Polar Flow', 'fi.polar.polarflow', 82),
    segment(addMinutes(bedtime, 230), 20, 'asleepCore', 'Polar Flow', 'fi.polar.polarflow', 82),
    segment(addMinutes(bedtime, 250), 10, 'awake', 'Polar Flow', 'fi.polar.polarflow'),
  ];
}

function buildDualSourceSegments(windowStart: Date): ISleepWearableSegment[] {
  const bedtime = addMinutes(windowStart, 20);
  const polar = buildDefaultNightSegments(addMinutes(windowStart, -10));
  const watchSegments: ISleepWearableSegment[] = [
    segment(bedtime, 240, 'asleepUnspecified', 'Apple Watch', 'com.apple.health.watch'),
  ];
  return [...polar, ...watchSegments];
}

function buildFragmentedSegments(windowStart: Date): ISleepWearableSegment[] {
  const bedtime = addMinutes(windowStart, 45);
  return [
    segment(bedtime, 40, 'asleepCore', 'Polar Flow', 'fi.polar.polarflow'),
    segment(addMinutes(bedtime, 40), 8, 'awake', 'Polar Flow', 'fi.polar.polarflow'),
    segment(addMinutes(bedtime, 48), 25, 'asleepCore', 'Polar Flow', 'fi.polar.polarflow'),
    segment(addMinutes(bedtime, 73), 12, 'awake', 'Polar Flow', 'fi.polar.polarflow'),
    segment(addMinutes(bedtime, 85), 35, 'asleepDeep', 'Polar Flow', 'fi.polar.polarflow'),
    segment(addMinutes(bedtime, 120), 6, 'awake', 'Polar Flow', 'fi.polar.polarflow'),
    segment(addMinutes(bedtime, 126), 50, 'asleepREM', 'Polar Flow', 'fi.polar.polarflow'),
  ];
}

function buildSegmentsForPreset(
  preset: TWearableMockPreset,
  windowStart: Date,
  windowEnd: Date,
): ISleepWearableSegment[] {
  if (preset === 'empty') {
    return [];
  }

  if (preset === 'fragmented') {
    return buildFragmentedSegments(windowStart);
  }

  if (preset === 'dualSource') {
    return buildDualSourceSegments(windowStart);
  }

  void windowEnd;
  return buildDefaultNightSegments(windowStart);
}

/** Мок-результат wearable за ночное окно */
export function loadMockWearableSleepNight(
  preset: TWearableMockPreset,
  windowStart: Date,
  windowEnd: Date,
): IWearableSleepNightResult {
  if (preset === 'denied') {
    return { status: 'denied' };
  }

  const rawSegments = buildSegmentsForPreset(preset, windowStart, windowEnd);
  if (rawSegments.length === 0) {
    return { status: 'no_data' };
  }

  const deduped = dedupeSleepSegments(rawSegments);
  const summary = aggregateWearableNight(deduped);
  if (summary === null) {
    return { status: 'no_data' };
  }

  return {
    status: 'available',
    summary,
  };
}

/** Мок-история за несколько ночей (для score / тренда) */
export function loadMockWearableSleepHistory(
  preset: TWearableMockPreset,
  windows: ISleepNightWindow[],
  schedule: INightSchedule = DEFAULT_NIGHT_SCHEDULE,
): IWearableSleepHistoryResult {
  if (preset === 'denied') {
    return { status: 'denied', nights: [] };
  }

  if (preset === 'empty') {
    return { status: 'no_data', nights: [] };
  }

  const allSegments: ISleepWearableSegment[] = [];
  for (const [index, window] of windows.entries()) {
    const jitterMinutes = (index % 5) * 8;
    const nightStart = addMinutes(window.startAt, jitterMinutes);
    const nightSegments = buildSegmentsForPreset(preset, nightStart, window.endAt);
    allSegments.push(...nightSegments);
  }

  if (allSegments.length === 0) {
    return { status: 'no_data', nights: [] };
  }

  const deduped = dedupeSleepSegments(allSegments);
  const nights = bucketWearableSegmentsByNight(deduped, windows, schedule);
  if (nights.length === 0) {
    return { status: 'no_data', nights: [] };
  }

  return { status: 'available', nights };
}

