import type {
  ISleepWearableNightSummary,
  ISleepWearableSegment,
} from '@/health/healthKitSleep.typings';
import { ASLEEP_WEARABLE_STAGES } from '@/health/wearableSleep.const';

/** Минимальный разрыв между asleep, мин — считаем пробуждением */
const ASLEEP_GAP_AWAKENING_MIN_MINUTES = 1;

function durationMinutes(startAt: Date, endAt: Date): number {
  return Math.max(0, (endAt.getTime() - startAt.getTime()) / 60_000);
}

function isAsleepStage(stage: ISleepWearableSegment['stage']): boolean {
  return ASLEEP_WEARABLE_STAGES.includes(stage);
}

/**
 * Минуты в кровати только из стадии inBed.
 * Fallback asleep+awake даёт efficiency=100 при отсутствии awake — сигнал бесполезен.
 */
export function resolveTimeInBedMinutes(
  summary: ISleepWearableNightSummary,
  _segments: ISleepWearableSegment[],
): number | undefined {
  void _segments;
  const inBed = summary.stageMinutes.inBed ?? 0;
  if (inBed <= 0) {
    return undefined;
  }
  return Math.round(inBed);
}

/** WASO и пробуждения: явный awake + разрывы между asleep */
export function measureSleepContinuity(segments: ISleepWearableSegment[]): {
  wasoMinutes: number;
  awakeningCount: number;
  /** Есть awake или разрывы — иначе continuity не считаем */
  hasSignal: boolean;
} {
  const relevant = segments
    .filter((segment) => segment.stage === 'awake' || isAsleepStage(segment.stage))
    .sort((a, b) => a.startAt.getTime() - b.startAt.getTime());

  const asleep = relevant.filter((segment) => isAsleepStage(segment.stage));
  if (asleep.length === 0) {
    return { wasoMinutes: 0, awakeningCount: 0, hasSignal: false };
  }

  const firstAsleepStart = asleep.reduce(
    (earliest, segment) => (segment.startAt < earliest ? segment.startAt : earliest),
    asleep[0].startAt,
  );
  const lastAsleepEnd = asleep.reduce(
    (latest, segment) => (segment.endAt > latest ? segment.endAt : latest),
    asleep[0].endAt,
  );

  let wasoMinutes = 0;
  let awakeningCount = 0;
  let hasAwake = false;

  for (const segment of relevant) {
    if (segment.stage !== 'awake') {
      continue;
    }
    hasAwake = true;
    if (segment.endAt <= firstAsleepStart || segment.startAt >= lastAsleepEnd) {
      continue;
    }
    const clippedStart = segment.startAt < firstAsleepStart ? firstAsleepStart : segment.startAt;
    const clippedEnd = segment.endAt > lastAsleepEnd ? lastAsleepEnd : segment.endAt;
    wasoMinutes += durationMinutes(clippedStart, clippedEnd);
  }

  for (let index = 1; index < relevant.length; index += 1) {
    const prev = relevant[index - 1];
    const current = relevant[index];
    if (isAsleepStage(prev.stage) && current.stage === 'awake') {
      if (current.startAt >= firstAsleepStart && current.startAt < lastAsleepEnd) {
        awakeningCount += 1;
      }
    }
  }

  let hasGaps = false;
  const asleepSorted = [...asleep].sort((a, b) => a.startAt.getTime() - b.startAt.getTime());
  for (let index = 1; index < asleepSorted.length; index += 1) {
    const prev = asleepSorted[index - 1];
    const current = asleepSorted[index];
    const gap = durationMinutes(prev.endAt, current.startAt);
    if (gap < ASLEEP_GAP_AWAKENING_MIN_MINUTES) {
      continue;
    }

    const gapCoveredByAwake = relevant.some(
      (segment) =>
        segment.stage === 'awake' &&
        segment.startAt < current.startAt &&
        segment.endAt > prev.endAt,
    );
    if (gapCoveredByAwake) {
      continue;
    }

    hasGaps = true;
    wasoMinutes += gap;
    awakeningCount += 1;
  }

  const hasSignal = hasAwake || hasGaps;

  return {
    wasoMinutes: Math.round(wasoMinutes),
    awakeningCount,
    hasSignal,
  };
}

/** Линейная интерполяция x из [x0,x1] в [y0,y1]; вне диапазона — clamp по концам */
export function lerpClamped(
  value: number,
  x0: number,
  x1: number,
  y0: number,
  y1: number,
): number {
  if (x1 === x0) {
    return y0;
  }
  if (value <= x0) {
    return y0;
  }
  if (value >= x1) {
    return y1;
  }
  const t = (value - x0) / (x1 - x0);
  return y0 + t * (y1 - y0);
}

/** Округление score 0–100 до целого */
export function clampScore(value: number): number {
  return Math.round(Math.max(0, Math.min(100, value)));
}

/** Медиана чисел; пустой массив → undefined */
export function median(values: number[]): number | undefined {
  if (values.length === 0) {
    return undefined;
  }
  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  if (sorted.length % 2 === 0) {
    return (sorted[mid - 1] + sorted[mid]) / 2;
  }
  return sorted[mid];
}

/** Выборочное стандартное отклонение; меньше 2 точек → 0 */
export function sampleStdDev(values: number[]): number {
  if (values.length < 2) {
    return 0;
  }
  const mean = values.reduce((sum, v) => sum + v, 0) / values.length;
  const variance =
    values.reduce((sum, v) => sum + (v - mean) ** 2, 0) / (values.length - 1);
  return Math.sqrt(variance);
}

import { useEffect, useRef } from 'react';
import {
  Modal,
  PanResponder,
  Pressable,
  ScrollView,
  Text,
  useWindowDimensions,
  View,
} from 'react-native';
import Animated, {
  runOnJS,
  useAnimatedStyle,
  useSharedValue,
  withTiming,
} from 'react-native-reanimated';
import { useSafeAreaInsets } from 'react-native-safe-area-context';

import { useThemeColors } from '@/hooks/useThemeColors';
import { typography } from '@/theme/tokens';

import {
  CALM_SHEET,
  CALM_SHEET_ANIMATION_MS,
  CALM_SHEET_DISMISS_DRAG_PX,
  CALM_SHEET_MAX_HEIGHT_RATIO,
} from './CalmSheet.const';
import type { ICalmSheetProps } from './CalmSheet.typings';
import { styles } from './CalmSheet.styles';

export function CalmSheet({ visible, title, subtitle, titleStyle, onClose, children }: ICalmSheetProps) {
  const c = useThemeColors();
  const insets = useSafeAreaInsets();
  const { height: windowHeight } = useWindowDimensions();
  const translateY = useSharedValue(windowHeight);
  const backdropOpacity = useSharedValue(0);
  const onCloseRef = useRef(onClose);

  onCloseRef.current = onClose;

  const dismissSheet = () => {
    onCloseRef.current();
  };

  useEffect(() => {
    if (visible) {
      translateY.value = withTiming(0, { duration: CALM_SHEET_ANIMATION_MS });
      backdropOpacity.value = withTiming(1, { duration: CALM_SHEET_ANIMATION_MS });
      return;
    }

    translateY.value = withTiming(windowHeight, { duration: CALM_SHEET_ANIMATION_MS });
    backdropOpacity.value = withTiming(0, { duration: CALM_SHEET_ANIMATION_MS });
  }, [visible, translateY, backdropOpacity, windowHeight]);

  const panResponder = useRef(
    PanResponder.create({
      onMoveShouldSetPanResponder: (_, gesture) => gesture.dy > 6,
      onPanResponderMove: (_, gesture) => {
        if (gesture.dy > 0) {
          translateY.value = gesture.dy;
        }
      },
      onPanResponderRelease: (_, gesture) => {
        if (gesture.dy > CALM_SHEET_DISMISS_DRAG_PX) {
          translateY.value = withTiming(windowHeight, { duration: CALM_SHEET_ANIMATION_MS }, () => {
            runOnJS(dismissSheet)();
          });
          backdropOpacity.value = withTiming(0, { duration: CALM_SHEET_ANIMATION_MS });
          return;
        }

        translateY.value = withTiming(0, { duration: CALM_SHEET_ANIMATION_MS });
      },
    }),
  ).current;

  const sheetAnimatedStyle = useAnimatedStyle(() => ({
    transform: [{ translateY: translateY.value }],
  }));

  const backdropAnimatedStyle = useAnimatedStyle(() => ({
    opacity: backdropOpacity.value,
  }));

  const maxSheetHeight = windowHeight * CALM_SHEET_MAX_HEIGHT_RATIO;

  return (
    <Modal
      visible={visible}
      transparent
      animationType="none"
      onRequestClose={onClose}
      testID={CALM_SHEET}
    >
      <View style={{ flex: 1 }}>
        <Pressable
          accessibilityRole="button"
          accessibilityLabel="Закрыть"
          onPress={onClose}
          style={{ flex: 1 }}
        >
          <Animated.View style={[styles.backdrop, backdropAnimatedStyle]} />
        </Pressable>

        <Animated.View
          style={[
            styles.sheet,
            sheetAnimatedStyle,
            {
              backgroundColor: c.surface,
              maxHeight: maxSheetHeight,
              paddingBottom: insets.bottom + 16,
            },
          ]}
        >
          <View style={styles.handleArea} {...panResponder.panHandlers}>
            <View style={[styles.handle, { backgroundColor: c.border }]} />
          </View>

          {title ? (
            <Text style={[typography.subtitle, styles.title, titleStyle, { color: c.text }]}>
              {title}
            </Text>
          ) : null}
          {subtitle ? (
            <Text style={[typography.caption, styles.subtitle, { color: c.textMuted }]}>
              {subtitle}
            </Text>
          ) : null}

          <ScrollView
            style={styles.content}
            keyboardShouldPersistTaps="handled"
            showsVerticalScrollIndicator={false}
          >
            {children}
          </ScrollView>
        </Animated.View>
      </View>
    </Modal>
  );
}

import type { ReactNode } from 'react';
import type { StyleProp, TextStyle } from 'react-native';

export interface ICalmSheetProps {
  /** Видимость sheet */
  visible: boolean;
  /** Заголовок; пустая строка — без title в шапке */
  title: string;
  /** Подзаголовок под title */
  subtitle?: string;
  /** Дополнительный стиль заголовка */
  titleStyle?: StyleProp<TextStyle>;
  /** Закрыть sheet */
  onClose: () => void;
  /** Содержимое */
  children: ReactNode;
}
